// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.nio.file.Path;
import java.util.Arrays;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

import org.eclipse.rdf4j.benchmark.common.ThemeQueryCatalog;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.queryrender.sparql.TupleExprIRRenderer;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.repository.util.RDFInserter;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbPharmaOptimizedQueryRegressionTest {

	private static final Theme THEME = Theme.PHARMA;
	private static final int MAX_QUERY_INDEX = 10;
	private static final String QUERY_INDEXES_PROPERTY = "rdf4j.lmdb.pharmaRegression.queryIndexes";
	private static final Pattern DIRECT_LOOKUP_WORK_ROWS = Pattern.compile(
			"StatementPattern \\([^)]*plannedWorkRows=([^,)]*)[^)]*plannedIndexAccessMode=directLookup");

	@Test
	void pharmaQueriesUsePlannerCostInvariants(@TempDir Path dataDir) throws Exception {
		Path themeDir = dataDir.resolve(THEME.name());
		LmdbStore store = new LmdbStore(themeDir.toFile(), ConfigUtil.createConfig());
		SailRepository repository = new SailRepository(store);
		try {
			BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
			loadData(repository);
			BenchmarkJoinEstimatorSupport.persistEstimatorAfterBulkLoad(repository, store);
			primeLearnedFilterStats(repository);
			BenchmarkJoinEstimatorSupport.persistStoreStatistics(store);
		} finally {
			shutdownAndRelease(repository, store);
		}

		store = new LmdbStore(themeDir.toFile(), ConfigUtil.createConfig());
		repository = new SailRepository(store);
		try {
			for (int queryIndex : queryIndexes()) {
				OptimizerSnapshot snapshot = explainOptimized(repository, queryIndex);
				assertPlannerCostInvariants(queryIndex, snapshot);
				BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
			}
		} finally {
			shutdownAndRelease(repository, store);
		}
	}

	private static void loadData(SailRepository repository) throws IOException {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			RDFInserter inserter = new RDFInserter(connection);
			for (Theme themeDataset : Theme.values()) {
				ThemeDataSetGenerator.generate(themeDataset, inserter);
			}
			connection.commit();
		}
	}

	private static void primeLearnedFilterStats(SailRepository repository) {
		for (int queryIndex = 0; queryIndex <= MAX_QUERY_INDEX; queryIndex++) {
			String query = ThemeQueryCatalog.queryFor(THEME, queryIndex);
			long expected = ThemeQueryCatalog.expectedCountFor(THEME, queryIndex);
			long actual = executeQuery(repository, query);
			if (actual != expected) {
				throw new AssertionError("Unable to prime learned filter stats for PHARMA query " + queryIndex
						+ ": expected=" + expected + ", actual=" + actual);
			}
		}
	}

	private static long executeQuery(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return connection.prepareTupleQuery(query)
					.evaluate()
					.stream()
					.count();
		}
	}

	private static List<Integer> queryIndexes() {
		String property = System.getProperty(QUERY_INDEXES_PROPERTY);
		if (property == null || property.isBlank()) {
			return IntStream.rangeClosed(0, MAX_QUERY_INDEX)
					.boxed()
					.collect(Collectors.toList());
		}
		return Arrays.stream(property.split(","))
				.map(String::trim)
				.filter(value -> !value.isEmpty())
				.map(Integer::parseInt)
				.collect(Collectors.toList());
	}

	private static OptimizerSnapshot explainOptimized(SailRepository repository, int queryIndex) {
		String query = ThemeQueryCatalog.queryFor(THEME, queryIndex);
		try (SailRepositoryConnection connection = repository.getConnection()) {
			Explanation explanation = connection.prepareTupleQuery(query)
					.explain(Explanation.Level.Optimized);
			return new OptimizerSnapshot(
					explanation.toString(),
					new TupleExprIRRenderer().render((TupleExpr) explanation.tupleExpr()));
		}
	}

	private static void assertPlannerCostInvariants(int queryIndex, OptimizerSnapshot snapshot) {
		String key = "PHARMA query " + queryIndex;
		assertTrue(snapshot.renderedQuery.contains("SELECT"), key + " should still render an optimized query");
		assertTrue(snapshot.plan.contains("plannerId=lmdb-sketch"), key + " should use LMDB sketch planning:\n"
				+ snapshot.plan);
		assertTrue(snapshot.plan.contains("plannerPath=ROBUST_USED"), key + " should use the robust planner path:\n"
				+ snapshot.plan);
		assertFalse(snapshot.plan.contains("plannerPath=UNSUPPORTED_SHAPE"),
				key + " should not reject supported segment shapes:\n" + snapshot.plan);
		assertDirectLookupWorkRowsBelow(snapshot.plan, 100_000.0d, key);
	}

	private static void assertDirectLookupWorkRowsBelow(String plan, double maxWorkRows, String key) {
		Matcher matcher = DIRECT_LOOKUP_WORK_ROWS.matcher(plan);
		while (matcher.find()) {
			double workRows = parsePlanRows(matcher.group(1));
			assertTrue(workRows <= maxWorkRows,
					key + " direct lookup plannedWorkRows should stay bounded by explicit step work, got "
							+ matcher.group(1) + "\n" + plan);
		}
	}

	private static double parsePlanRows(String value) {
		String trimmed = value.trim();
		double multiplier = 1.0d;
		if (trimmed.endsWith("K")) {
			multiplier = 1_000.0d;
			trimmed = trimmed.substring(0, trimmed.length() - 1);
		} else if (trimmed.endsWith("M")) {
			multiplier = 1_000_000.0d;
			trimmed = trimmed.substring(0, trimmed.length() - 1);
		} else if (trimmed.endsWith("B")) {
			multiplier = 1_000_000_000.0d;
			trimmed = trimmed.substring(0, trimmed.length() - 1);
		}
		return Double.parseDouble(trimmed) * multiplier;
	}

	private static void shutdownAndRelease(SailRepository repository, LmdbStore store) throws IOException {
		try {
			BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
		} finally {
			repository.shutDown();
		}
	}

	private static final class OptimizerSnapshot {
		private final String plan;
		private final String renderedQuery;

		private OptimizerSnapshot(String plan, String renderedQuery) {
			this.plan = plan;
			this.renderedQuery = renderedQuery;
		}
	}
}
